/* ==========================================================================
   PERFECT WORLD — AAA Gaming Website
   Inspired by Genshin Impact, Lost Ark, Black Desert Online
   ========================================================================== */

const SHOWCASE_CLASSES: ClassData[] = [
  {
    id: 'blademaster',
    name: 'Blademaster',
    role: 'damage_dealer',
    description: 'Master of melee combat with devastating sword techniques and high burst damage output.',
    artwork: '/images/classes/blademaster.png',
    primaryAbilities: ['Whirlwind Strike', 'Blade Dance', 'Execution'],
    playstyleSummary: 'Fast-paced, aggressive playstyle requiring precise timing and positioning.',
    model3D: 'https://example.com/blademaster.glb',
  },
  {
    id: 'wizard',
    name: 'Wizard',
    role: 'damage_dealer',
    description: 'Harness the power of magic to rain destruction upon your enemies from a safe distance.',
    artwork: '/images/classes/wizard.png',
    primaryAbilities: ['Fireball', 'Frost Nova', 'Meteor Storm'],
    playstyleSummary: 'Ranged caster with powerful area control and crowd control abilities.',
    model3D: 'https://example.com/wizard.glb',
  },
  {
    id: 'cleric',
    name: 'Cleric',
    role: 'healer',
    description: 'Divine healer who mends wounds and protects allies with holy magic and blessings.',
    artwork: '/images/classes/cleric.png',
    primaryAbilities: ['Holy Light', 'Divine Shield', 'Resurrection'],
    playstyleSummary: 'Support-focused with strong defensive capabilities and group healing.',
    model3D: 'https://example.com/cleric.glb',
  },
  {
    id: 'barbarian',
    name: 'Barbarian',
    role: 'tank',
    description: 'Unstoppable force that absorbs massive damage and taunts enemies to protect the group.',
    artwork: '/images/classes/barbarian.png',
    primaryAbilities: ['Charge', 'Taunt', 'Whirlwind Defense'],
    playstyleSummary: 'Tanky frontline with crowd control and threat management.',
    model3D: 'https://example.com/barbarian.glb',
  },
  {
    id: 'archer',
    name: 'Archer',
    role: 'damage_dealer',
    description: 'Precision striker who deals consistent ranged damage with deadly accuracy and mobility.',
    artwork: '/images/classes/archer.png',
    primaryAbilities: ['Multi-Shot', 'Piercing Arrow', 'Rain of Arrows'],
    playstyleSummary: 'Mobile ranged DPS with high attack speed and evasion.',
    model3D: 'https://example.com/archer.glb',
  },
  {
    id: 'psychic',
    name: 'Psychic',
    role: 'support',
    description: 'Master of mental powers who controls the battlefield with psychic abilities and buffs.',
    artwork: 'https://images.unsplash.com/photo-1511512578047-dfb367046420?w=600&q=80',
    primaryAbilities: ['Mind Control', 'Psychic Barrier', 'Amplify'],
    playstyleSummary: 'Support caster with crowd control and party enhancement.',
    model3D: 'https://example.com/psychic.glb',
  },
];

export default function HomePage() {
  const [onlinePlayerCount, setOnlinePlayerCount] = useState<number | undefined>(
    undefined
  );
  const [isLoadingPlayerCount, setIsLoadingPlayerCount] = useState(false);

  // Simulate fetching player count from server status widget
  useEffect(() => {
    setIsLoadingPlayerCount(true);
    // Simulate API call
    const timer = setTimeout(() => {
      setOnlinePlayerCount(12847);
      setIsLoadingPlayerCount(false);
    }, 1000);

    return () => clearTimeout(timer);
  }, []);

  return (
    <main
      style={{
        background: 'transparent',
        color: '#1a1a2e',
        minHeight: '100vh',
        overflow: 'hidden',
      }}
    >
      {/* ===== HERO SECTION ===== */}
      <HeroSection
        onlinePlayerCount={onlinePlayerCount}
        isLoadingPlayerCount={isLoadingPlayerCount}
      />

      {/* ===== FEATURES SECTION ===== */}
      <section
        style={{
          padding: 'clamp(80px, 10vw, 128px) 24px',
          background: 'transparent',
        }}
      >
        <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
          {/* Section Title */}
          <h2
            style={{
              textAlign: 'center',
              fontSize: 'clamp(24px, 3vw, 40px)',
              fontWeight: 700,
              letterSpacing: '0.05em',
              marginBottom: '64px',
              color: '#ffffff',
              textShadow: '0 2px 10px rgba(0,0,0,0.3)',
            }}
          >
            FORGE YOUR DESTINY
          </h2>

          {/* Feature Cards */}
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
              gap: '24px',
            }}
          >
            {[
              {
                title: 'Epic Battles',
                description: 'Massive PvP warfare with hundreds of players clashing in real-time sieges.',
                image: 'https://images.unsplash.com/photo-1542751371-adc38448a05e?w=600&q=80',
              },
              {
                title: 'Living World',
                description: 'A breathing open world that evolves with every season and player action.',
                image: 'https://images.unsplash.com/photo-1511512578047-dfb367046420?w=600&q=80',
              },
              {
                title: 'Your Story',
                description: 'Shape your legend through choices that permanently alter your journey.',
                image: 'https://images.unsplash.com/photo-1538481199705-c710c4e965fc?w=600&q=80',
              },
            ].map((feature, index) => (
              <div
                key={index}
                className="glass-card glass-card-interactive"
                style={{
                  position: 'relative',
                  height: '300px',
                  overflow: 'hidden',
                  cursor: 'pointer',
                }}
                onMouseEnter={(e) => {
                  const img = e.currentTarget.querySelector('div[data-img]') as HTMLElement;
                  if (img) img.style.transform = 'scale(1.1)';
                }}
                onMouseLeave={(e) => {
                  const img = e.currentTarget.querySelector('div[data-img]') as HTMLElement;
                  if (img) img.style.transform = 'scale(1)';
                }}
              >
                <div
                  data-img="true"
                  style={{
                    position: 'absolute',
                    inset: 0,
                    backgroundImage: `url(${feature.image})`,
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                    transition: 'transform 0.3s ease',
                  }}
                />
                <div
                  style={{
                    position: 'absolute',
                    inset: 0,
                    background: 'linear-gradient(to top, rgba(10,10,15,0.95) 0%, rgba(10,10,15,0.2) 60%)',
                  }}
                />
                <div
                  style={{
                    position: 'absolute',
                    bottom: 0,
                    left: 0,
                    right: 0,
                    padding: '32px',
                  }}
                >
                  <h3
                    style={{
                      fontSize: '20px',
                      fontWeight: 700,
                      margin: '0 0 8px 0',
                      color: '#ffffff',
                    }}
                  >
                    {feature.title}
                  </h3>
                  <p
                    style={{
                      fontSize: '14px',
                      color: 'rgba(255,255,255,0.9)',
                      margin: 0,
                      lineHeight: 1.6,
                      textShadow: '0 1px 2px rgba(0,0,0,0.3)',
                    }}
                  >
                    {feature.description}
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ===== CLASS SHOWCASE SECTION ===== */}
      <ClassShowcase classes={SHOWCASE_CLASSES} />

      {/* ===== NEWS SECTION ===== */}
      <section
        style={{
          padding: 'clamp(80px, 10vw, 128px) 24px',
          background: '#F6F6F6',
        }}
      >
        <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
          {/* Section Header */}
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              marginBottom: '48px',
            }}
          >
            <h2
              style={{
                fontSize: 'clamp(24px, 3vw, 40px)',
                fontWeight: 700,
                letterSpacing: '0.05em',
                color: '#111111',
                margin: 0,
              }}
            >
              LATEST NEWS
            </h2>
            <Link
              href="/news"
              style={{
                fontSize: '14px',
                color: '#555555',
                textDecoration: 'none',
                transition: 'color 0.3s ease',
              }}
              onMouseEnter={(e) => { e.currentTarget.style.color = '#00d4ff'; }}
              onMouseLeave={(e) => { e.currentTarget.style.color = '#7a7a8a'; }}
            >
              View All →
            </Link>
          </div>

          {/* News Items */}
          <div style={{ display: 'flex', flexDirection: 'column' }}>
            {[
              {
                date: 'Dec 15, 2024',
                category: 'Update',
                title: 'Season 4: Twilight Dominion launches with new territory wars',
              },
              {
                date: 'Dec 12, 2024',
                category: 'Event',
                title: 'Winter Solstice Festival brings exclusive mounts and cosmetics',
              },
              {
                date: 'Dec 8, 2024',
                category: 'Balance',
                title: 'Class rebalancing patch addresses Wizard burst damage concerns',
              },
            ].map((news, index) => (
              <div
                key={index}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '20px',
                  padding: '20px 0',
                  borderBottom: index < 2 ? '1px solid #E0E0E0' : 'none',
                  cursor: 'pointer',
                  transition: 'all 0.3s ease',
                }}
                onMouseEnter={(e) => {
                  const title = e.currentTarget.querySelector('span[data-title]') as HTMLElement;
                  if (title) title.style.color = '#00d4ff';
                }}
                onMouseLeave={(e) => {
                  const title = e.currentTarget.querySelector('span[data-title]') as HTMLElement;
                  if (title) title.style.color = '#ffffff';
                }}
              >
                <span
                  style={{
                    fontSize: '13px',
                    color: '#555555',
                    whiteSpace: 'nowrap',
                    minWidth: '100px',
                  }}
                >
                  {news.date}
                </span>
                <span
                  style={{
                    fontSize: '10px',
                    fontWeight: 600,
                    letterSpacing: '0.1em',
                    textTransform: 'uppercase',
                    padding: '4px 10px',
                    background: 'rgba(0, 212, 255, 0.1)',
                    color: '#00d4ff',
                    whiteSpace: 'nowrap',
                  }}
                >
                  {news.category}
                </span>
                <span
                  data-title="true"
                  style={{
                    fontSize: '15px',
                    color: '#111111',
                    transition: 'color 0.3s ease',
                  }}
                >
                  {news.title}
                </span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ===== RANKINGS PREVIEW SECTION ===== */}
      <section
        style={{
          padding: 'clamp(80px, 10vw, 128px) 24px',
          background: '#FFFFFF',
        }}
      >
        <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
          {/* Section Header */}
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              marginBottom: '48px',
              flexWrap: 'wrap',
              gap: '16px',
            }}
          >
            <h2
              style={{
                fontSize: 'clamp(24px, 3vw, 40px)',
                fontWeight: 700,
                letterSpacing: '0.05em',
                color: '#ffffff',
                margin: 0,
              }}
            >
              TOP PLAYERS
            </h2>
            <Link
              href="/rankings"
              style={{
                fontSize: '14px',
                color: '#7a7a8a',
                textDecoration: 'none',
                transition: 'color 0.3s ease',
              }}
              onMouseEnter={(e) => { e.currentTarget.style.color = '#00d4ff'; }}
              onMouseLeave={(e) => { e.currentTarget.style.color = '#7a7a8a'; }}
            >
              View All Rankings →
            </Link>
          </div>

          {/* Rankings Preview */}
          <RankingsPreview
            category="players"
            entries={[
              { rank: 1, name: 'ShadowReaper', score: 98750, guild: 'Eclipse Order' },
              { rank: 2, name: 'CelestialBlade', score: 95200, guild: 'Heavenly Sword' },
              { rank: 3, name: 'VoidWalker', score: 93100, guild: 'Eclipse Order' },
              { rank: 4, name: 'PhoenixRise', score: 89400, guild: 'Crimson Wings' },
